          LDA $BD5A,X                     ; $0A6B BD 5A BD
          LDX $27                         ; $0A6E A6 27
          JSR $BA92                       ; $0A70 20 92 BA
          LDA #$DE                        ; $0A73 A9 DE
          JSR $BA8F                       ; $0A75 20 8F BA
